user_intent:
from sklearn.base import BaseEstimator, TransformerMixin
from sklearn.base import BaseEstimator
import pandas as pd
from sklearn.pipeline import Pipeline
from sklearn import datasets

simple_cols = ['sepal length (cm)', 'sepal width (cm)', 'petal length (cm)', 'petal width (cm)']

class ColumnSelectTransformer(BaseEstimator, TransformerMixin):
    def __init__(self, columns):
        self.columns = columns

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        if not isinstance(X, pd.DataFrame):
            X = pd.DataFrame(X)
        X.dropna(inplace=True)
        return X[self.columns].values()

def test():
    iris = datasets.load_iris(as_frame=True)
    simple_features = Pipeline([
        ('cst', ColumnSelectTransformer(simple_cols)),
    ])
    X = iris.data
    simple_features.fit_transform(X)

user_intent_transformed:
from sklearn.base import BaseEstimator, TransformerMixin
from sklearn.base import BaseEstimator
import pandas as pd
from sklearn.pipeline import Pipeline
from sklearn import datasets

simple_cols = ['sepal length (cm)', 'sepal width (cm)', 'petal length (cm)', 'petal width (cm)']

class ColumnSelectTransformer(BaseEstimator, TransformerMixin):
    def __init__(self, columns):
        self.columns = columns

    def fit(self, X, y=None):
        return self

    def transform(self, X):
        if not isinstance(X, pd.DataFrame):
            X = pd.DataFrame(X)
        X.dropna(inplace=True)
        return X[self.columns].values()

def test():
    iris = datasets.load_iris(as_frame=True)
    simple_features = Pipeline([
        ('cst', ColumnSelectTransformer(simple_cols)),
    ])
    X = iris.data
    simple_features.fit_transform(X)

context:
To connect to a MySQL database using PHP, you can use the following code snippet:

```php
<?php
$servername = "localhost";
$username = "username";
$password = "password";
$dbname = "database_name";

// Create connection
$conn = new mysqli($servername, $username, $password, $dbname);

// Check connection
if ($conn->connect_error) {
    die("Connection failed: " . $conn->connect_error);
}
echo "Connected successfully";

// Close connection
$conn->close();
?>
```

